import initSqlJs, { Database, SqlJsStatic } from 'sql.js';

let SQL: SqlJsStatic | null = null;
let db: Database | null = null;

const DB_KEY = 'automate-sqlite-db';

async function initSQL(): Promise<SqlJsStatic> {
  if (!SQL) {
    const wasmUrl = '/sql-wasm.wasm';
    const response = await fetch(wasmUrl);
    const wasmBinary = await response.arrayBuffer();
    
    SQL = await initSqlJs({
      wasmBinary
    });
  }
  return SQL;
}

function saveToLocalStorage(): void {
  if (!db) return;
  const data = db.export();
  const buffer = new Uint8Array(data);
  localStorage.setItem(DB_KEY, btoa(String.fromCharCode(...buffer)));
}

function loadFromLocalStorage(): Uint8Array | null {
  const stored = localStorage.getItem(DB_KEY);
  if (!stored) return null;
  const binary = atob(stored);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

export async function initDatabase(): Promise<Database> {
  if (db) return db;

  const SqlJs = await initSQL();
  const savedData = loadFromLocalStorage();

  if (savedData) {
    db = new SqlJs.Database(savedData);
  } else {
    db = new SqlJs.Database();
    createTables(db);
    saveToLocalStorage();
  }

  return db;
}

function createTables(database: Database): void {
  database.run(`
    CREATE TABLE IF NOT EXISTS chat_messages (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      agent_id VARCHAR(255) NOT NULL,
      agent_name VARCHAR(255) NOT NULL,
      user_id VARCHAR(255) NOT NULL,
      user_name VARCHAR(255) NOT NULL,
      content TEXT NOT NULL,
      message_type VARCHAR(50) NOT NULL,
      send_time DATETIME DEFAULT CURRENT_TIMESTAMP,
      status VARCHAR(50) DEFAULT 'sent',
      message_length INTEGER DEFAULT 0,
      has_attachment BOOLEAN DEFAULT 0,
      attachment_path TEXT,
      skill_activated VARCHAR(255),
      thinking_content TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  `);

  database.run(`
    CREATE TABLE IF NOT EXISTS skill_calls (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      message_id INTEGER,
      agent_id VARCHAR(255) NOT NULL,
      skill_name VARCHAR(255) NOT NULL,
      parameters TEXT,
      call_time DATETIME DEFAULT CURRENT_TIMESTAMP,
      status VARCHAR(50) DEFAULT 'pending',
      result TEXT,
      execution_time INTEGER DEFAULT 0,
      error_message TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (message_id) REFERENCES chat_messages(id) ON DELETE CASCADE
    )
  `);

  database.run(`CREATE INDEX IF NOT EXISTS idx_chat_messages_agent_id ON chat_messages(agent_id)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_chat_messages_send_time ON chat_messages(send_time)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_chat_messages_agent_send_time ON chat_messages(agent_id, send_time DESC)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_chat_messages_user_id ON chat_messages(user_id)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_chat_messages_message_type ON chat_messages(message_type)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_chat_messages_status ON chat_messages(status)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_chat_messages_skill_activated ON chat_messages(skill_activated)`);

  database.run(`CREATE INDEX IF NOT EXISTS idx_skill_calls_message_id ON skill_calls(message_id)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_skill_calls_call_time ON skill_calls(call_time)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_skill_calls_message_time ON skill_calls(message_id, call_time DESC)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_skill_calls_agent_id ON skill_calls(agent_id)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_skill_calls_skill_name ON skill_calls(skill_name)`);
  database.run(`CREATE INDEX IF NOT EXISTS idx_skill_calls_status ON skill_calls(status)`);
}

export interface ChatMessageRow {
  id: number;
  agent_id: string;
  agent_name: string;
  user_id: string;
  user_name: string;
  content: string;
  message_type: string;
  send_time: string;
  status: string;
  message_length: number;
  has_attachment: number;
  attachment_path: string | null;
  skill_activated: string | null;
  thinking_content: string | null;
  created_at: string;
  updated_at: string;
}

export interface SkillCallRow {
  id: number;
  message_id: number | null;
  agent_id: string;
  skill_name: string;
  parameters: string | null;
  call_time: string;
  status: string;
  result: string | null;
  execution_time: number;
  error_message: string | null;
  created_at: string;
  updated_at: string;
}

export async function saveMessageToSQLite(
  agentId: string,
  agentName: string,
  content: string,
  messageType: 'user' | 'assistant' | 'system',
  skillActivated?: string,
  thinkingContent?: string,
  status: string = 'sent'
): Promise<number> {
  const database = await initDatabase();
  const now = new Date().toISOString();

  database.run(
    `INSERT INTO chat_messages 
     (agent_id, agent_name, user_id, user_name, content, message_type, send_time, status, message_length, has_attachment, skill_activated, thinking_content, created_at, updated_at) 
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    [
      agentId,
      agentName,
      'default_user',
      '用户',
      content,
      messageType,
      now,
      status,
      content.length,
      0,
      skillActivated || null,
      thinkingContent || null,
      now,
      now
    ]
  );

  const result = database.exec('SELECT last_insert_rowid() as id');
  const id = result[0]?.values[0]?.[0] as number;

  saveToLocalStorage();
  console.log('[SQLite] 消息保存成功, id:', id);
  return id;
}

export async function getMessagesFromSQLite(
  agentId: string,
  since?: Date
): Promise<ChatMessageRow[]> {
  const database = await initDatabase();

  let query = 'SELECT * FROM chat_messages WHERE agent_id = ?';
  const params: (string | number)[] = [agentId];

  if (since) {
    query += ' AND send_time >= ?';
    params.push(since.toISOString());
  }

  query += ' ORDER BY send_time ASC';

  const result = database.exec(query, params);
  if (!result[0]) return [];

  const columns = result[0].columns;
  return result[0].values.map((row: (string | number | null | Uint8Array)[]) => {
    const obj: Record<string, string | number | null | Uint8Array> = {};
    columns.forEach((col: string, idx: number) => {
      const val = row[idx];
      obj[col] = val instanceof Uint8Array ? null : val;
    });
    return obj as unknown as ChatMessageRow;
  });
}

export async function deleteMessageFromSQLite(id: number): Promise<void> {
  const database = await initDatabase();
  database.run('DELETE FROM chat_messages WHERE id = ?', [id]);
  saveToLocalStorage();
}

export async function deleteLastAiMessageFromSQLite(agentId: string): Promise<number | null> {
  const database = await initDatabase();

  const result = database.exec(
    'SELECT id FROM chat_messages WHERE agent_id = ? AND message_type = ? ORDER BY send_time DESC LIMIT 1',
    [agentId, 'assistant']
  );

  if (result[0]?.values[0]) {
    const id = result[0].values[0][0] as number;
    database.run('DELETE FROM chat_messages WHERE id = ?', [id]);
    saveToLocalStorage();
    return id;
  }

  return null;
}

export async function saveSkillCallToSQLite(
  agentId: string,
  skillName: string,
  messageId?: number,
  parameters?: Record<string, unknown>,
  status: 'pending' | 'success' | 'failed' | 'timeout' = 'pending'
): Promise<number> {
  const database = await initDatabase();
  const now = new Date().toISOString();

  database.run(
    `INSERT INTO skill_calls 
     (message_id, agent_id, skill_name, parameters, call_time, status, execution_time, created_at, updated_at) 
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    [
      messageId || null,
      agentId,
      skillName,
      parameters ? JSON.stringify(parameters) : null,
      now,
      status,
      0,
      now,
      now
    ]
  );

  const result = database.exec('SELECT last_insert_rowid() as id');
  const id = result[0]?.values[0]?.[0] as number;

  saveToLocalStorage();
  return id;
}

export async function getSkillCallsFromSQLite(
  agentId: string,
  messageId?: number
): Promise<SkillCallRow[]> {
  const database = await initDatabase();

  let query = 'SELECT * FROM skill_calls WHERE agent_id = ?';
  const params: (string | number)[] = [agentId];

  if (messageId !== undefined) {
    query += ' AND message_id = ?';
    params.push(messageId);
  }

  query += ' ORDER BY call_time ASC';

  const result = database.exec(query, params);
  if (!result[0]) return [];

  const columns = result[0].columns;
  return result[0].values.map((row: (string | number | null | Uint8Array)[]) => {
    const obj: Record<string, string | number | null | Uint8Array> = {};
    columns.forEach((col: string, idx: number) => {
      const val = row[idx];
      obj[col] = val instanceof Uint8Array ? null : val;
    });
    return obj as unknown as SkillCallRow;
  });
}

